$blogDir = 'c:\Users\HOLA\OneDrive\Escritorio\juristam-web\blog'
$utf8noBOM = New-Object System.Text.UTF8Encoding $false
$updated = 0; $skipped = 0; $notFound = 0

function Find-ArrayClose($str, $startPos) {
    $openPos = $str.IndexOf('[', $startPos)
    if ($openPos -lt 0) { return -1 }
    $depth = 0; $inStr = $false; $esc = $false
    $bsc = [int][char]92; $dqc = [int][char]34
    for ($i = $openPos; $i -lt $str.Length; $i++) {
        $ci = [int][char]$str[$i]
        if ($esc) { $esc = $false; continue }
        if ($ci -eq $bsc -and $inStr) { $esc = $true; continue }
        if ($ci -eq $dqc) { $inStr = !$inStr; continue }
        if (-not $inStr) {
            if ($str[$i] -eq '[') { $depth++ }
            elseif ($str[$i] -eq ']') { $depth--; if ($depth -eq 0) { return $i } }
        }
    }
    return -1
}

function Add-FaqData($filename, $jsonAdd, $htmlAdd) {
    $path = Join-Path $blogDir $filename
    if (-not (Test-Path $path)) { $script:notFound++; Write-Host "NOT FOUND: $filename"; return }
    $c = [System.IO.File]::ReadAllText($path, [System.Text.Encoding]::UTF8)
    $marker = $jsonAdd.Substring(0,[Math]::Min(50,$jsonAdd.Length))
    if ($c.IndexOf($marker) -ge 0) { $script:skipped++; Write-Host "SKIP: $filename"; return }
    $tag = '<script type="application/ld+json">'
    $si = $c.IndexOf($tag); $ei = $c.IndexOf('</script>', $si)
    if ($si -ge 0) {
        $jb = $c.Substring($si+$tag.Length, $ei-$si-$tag.Length)
        $fp = $jb.IndexOf('"FAQPage"')
        if ($fp -ge 0) {
            $mp = $jb.IndexOf('"mainEntity"', $fp)
            $cl = Find-ArrayClose $jb $mp
            if ($cl -ge 0) {
                $abs = $si+$tag.Length+$cl
                $c = $c.Substring(0,$abs) + ',' + $jsonAdd + $c.Substring($abs)
            }
        }
    }
    $ld = $c.LastIndexOf('</details>')
    if ($ld -ge 0) {
        $cd = $c.IndexOf('</div>', $ld+10)
        if ($cd -ge 0) { $c = $c.Substring(0,$cd) + $htmlAdd + "`n" + $c.Substring($cd) }
    }
    [System.IO.File]::WriteAllText($path, $c, $utf8noBOM)
    $script:updated++; Write-Host "OK: $filename"
}

Add-FaqData 'antecedentes-judiciales-ecuador.html' `
'{"@type":"Question","name":"Mi proceso terminó hace años pero sigo apareciendo en el SATJE, ¿eso es normal?","acceptedAnswer":{"@type":"Answer","text":"Sí, es completamente normal y es uno de los problemas más frecuentes en Ecuador. El SATJE no elimina automáticamente tu nombre cuando el proceso termina — el archivo, el sobreseimiento o la conciliación cierran el expediente, pero tu nombre sigue visible en la consulta pública. La Resolución 043-2024 del Consejo de la Judicatura creó el mecanismo legal para corregir esto: el ocultamiento de datos personales en procesos judiciales. Juristam tramita el ocultamiento completo desde $250."}},{"@type":"Question","name":"¿Cualquier persona puede ver mis antecedentes judiciales en el SATJE sin mi permiso?","acceptedAnswer":{"@type":"Answer","text":"Sí. El SATJE es una plataforma pública y gratuita: cualquier persona, empresa, banco o entidad que escriba tu nombre o cédula en consultas.funcionjudicial.gob.ec puede ver todos tus procesos judiciales registrados. El sistema no exige ningún tipo de autorización del titular. Esto es lo que la Resolución 043-2024 busca corregir a través del mecanismo de ocultamiento que gestionan firmas especializadas como Juristam."}},{"@type":"Question","name":"¿Qué diferencia hay entre ocultar el SATJE y ocultar Fiscalía?","acceptedAnswer":{"@type":"Answer","text":"Son dos sistemas completamente distintos que requieren trámites separados. El SATJE lo administra la Función Judicial y el ocultamiento se tramita ante el juez que conoció la causa, bajo la Resolución 043-2024. Fiscalía tiene su propio sistema llamado SIAF, y el ocultamiento allá se tramita ante la Dirección Jurídica de Fiscalía bajo la Resolución 027-FGE-2024. Muchas personas tienen registros en ambos sistemas sin saberlo. En Juristam revisamos los dos sistemas en la asesoría inicial para determinar en cuál o cuáles apareces."}},{"@type":"Question","name":"¿El ocultamiento del SATJE borra el proceso o solo lo esconde?","acceptedAnswer":{"@type":"Answer","text":"Solo lo oculta de la consulta pública — no lo elimina. El expediente sigue existiendo dentro del sistema interno de la Función Judicial y los jueces y secretarios con acceso oficial todavía pueden verlo por número de causa. Lo que desaparece es la asociación de tu nombre y cédula al proceso en el buscador público. Para efectos prácticos — empleos, créditos, visas — el resultado es el mismo que si no existiera, porque quienes consultan acceden al portal público."}},{"@type":"Question","name":"¿El SATJE afecta la aprobación de un crédito bancario en Ecuador?","acceptedAnswer":{"@type":"Answer","text":"Sí, directamente. Los bancos y cooperativas en Ecuador consultan el SATJE como parte de su proceso de evaluación de riesgo. Un proceso judicial visible — aunque haya terminado a tu favor — puede ser interpretado como señal de riesgo y llevar a la negación del crédito. El ocultamiento en el SATJE elimina esa visibilidad y, con ello, ese obstáculo. Juristam ha tramitado casos donde el cliente obtuvo el crédito que le habían negado después de completar el ocultamiento."}},{"@type":"Question","name":"¿Cuánto cuesta ocultar los antecedentes del SATJE en Ecuador?","acceptedAnswer":{"@type":"Answer","text":"Juristam cobra $45 por la asesoría inicial (virtual) o $85 presencial, valor que se descuenta del servicio completo. El ocultamiento solo en el SATJE cuesta $250; solo en Fiscalía $250; y el combo SATJE + Fiscalía $400. Estos precios incluyen la preparación del escrito, la presentación ante el juzgado, el seguimiento del trámite y la verificación final de que tu nombre ya no aparece en la consulta pública."}},{"@type":"Question","name":"¿El ocultamiento funciona si mi proceso fue en Quito pero ahora vivo en Guayaquil?","acceptedAnswer":{"@type":"Answer","text":"Sí. La solicitud se presenta ante el juzgado que conoció la causa, no donde vives ahora. Si el proceso fue en Quito, el escrito va a Quito — pero con representación legal no necesitas ir en persona. Juristam puede gestionar el trámite completo en cualquier ciudad del Ecuador sin que el cliente tenga que desplazarse, mediante poder notarial que puede otorgarse en cualquier notaría del país."}},{"@type":"Question","name":"¿Cuánto tiempo tarda en desaparecer mi nombre del SATJE una vez presentada la solicitud?","acceptedAnswer":{"@type":"Answer","text":"El proceso completo toma entre 10 y 30 días hábiles dependiendo de la ciudad. Guayaquil y Quito tienen mayor congestión judicial y pueden tomar hasta 30 días hábiles; ciudades más pequeñas entre 10 y 20. El plazo se divide en: preparación del escrito (2-5 días), admisión (1-3 días), análisis y resolución del juez (5-20 días) y ejecución del secretario en el sistema (1-3 días). Juristam hace seguimiento activo en cada etapa para detectar demoras y actuar de inmediato."}},{"@type":"Question","name":"¿Un proceso archivado hace 10 años califica para el ocultamiento?","acceptedAnswer":{"@type":"Answer","text":"Sí. La antigüedad del proceso no impide el ocultamiento. La Resolución 043-2024 no establece un plazo máximo desde el cierre del proceso — lo que importa es el estado actual: archivado, sobreseído, absuelto, conciliación cumplida o extinguido. Juristam ha tramitado ocultamientos de procesos de hace más de 10 años sin ningún obstáculo adicional por la antigüedad."}},{"@type":"Question","name":"¿El ocultamiento del SATJE es permanente o se puede revertir?","acceptedAnswer":{"@type":"Answer","text":"Es permanente. Una vez que el secretario ejecuta la anonimización en el sistema, tu nombre deja de aparecer en las búsquedas públicas de forma definitiva. La Resolución 043-2024 no establece ningún mecanismo de reversión automática. El único escenario que podría volver a hacerte visible es que enfrentes un nuevo proceso judicial, pero ese sería un expediente distinto — el anterior permanece oculto."}},{"@type":"Question","name":"¿Puedo hacer el trámite de ocultamiento del SATJE yo mismo sin abogado?","acceptedAnswer":{"@type":"Answer","text":"Técnicamente no existe una prohibición expresa, pero en la práctica es muy difícil hacerlo solo. El escrito debe fundamentarse correctamente en la Resolución 043-2024, el Art. 66 de la Constitución y la Ley Orgánica de Protección de Datos Personales, con la identificación precisa del proceso y la argumentación de por qué afecta tus derechos. Un escrito mal fundamentado resulta en rechazo aunque el caso califique perfectamente. Juristam prepara el escrito con la fundamentación técnica que los jueces aceptan."}},{"@type":"Question","name":"¿Si fui sobreseído definitivamente puedo ocultar el proceso del SATJE?","acceptedAnswer":{"@type":"Answer","text":"Sí, y el sobreseimiento definitivo es la causal más sólida para el ocultamiento. La Resolución 043-2024 reconoce expresamente que cuando el proceso terminó sin responsabilidad penal establecida, el titular tiene un derecho reforzado a la protección de sus datos. Juristam tramita estos casos con alta tasa de aprobación porque el fundamento jurídico es el más robusto dentro del sistema de ocultamiento."}}' `
'<details><summary>Mi proceso terminó hace años pero sigo apareciendo en el SATJE, ¿eso es normal?</summary><p class="faq-answer">Sí, es completamente normal y es uno de los problemas más frecuentes en Ecuador. El SATJE no elimina automáticamente tu nombre cuando el proceso termina. La Resolución 043-2024 creó el mecanismo legal para corregir esto. Juristam tramita el ocultamiento completo desde $250.</p></details>
<details><summary>¿Cualquier persona puede ver mis antecedentes judiciales en el SATJE sin mi permiso?</summary><p class="faq-answer">Sí. El SATJE es una plataforma pública y gratuita: cualquier persona que escriba tu nombre o cédula puede ver todos tus procesos judiciales. El sistema no exige autorización del titular. La Resolución 043-2024 busca corregir esto a través del mecanismo de ocultamiento.</p></details>
<details><summary>¿Qué diferencia hay entre ocultar el SATJE y ocultar Fiscalía?</summary><p class="faq-answer">Son dos sistemas distintos que requieren trámites separados. El SATJE se tramita ante el juez bajo la Resolución 043-2024. Fiscalía tiene su propio sistema (SIAF) bajo la Resolución 027-FGE-2024. Muchas personas tienen registros en ambos sin saberlo. Juristam revisa los dos en la asesoría inicial.</p></details>
<details><summary>¿El ocultamiento del SATJE borra el proceso o solo lo esconde?</summary><p class="faq-answer">Solo lo oculta de la consulta pública — no lo elimina. El expediente sigue existiendo para jueces y secretarios con acceso oficial. Lo que desaparece es la asociación de tu nombre y cédula en el buscador público.</p></details>
<details><summary>¿El SATJE afecta la aprobación de un crédito bancario en Ecuador?</summary><p class="faq-answer">Sí, directamente. Los bancos consultan el SATJE como parte de la evaluación de riesgo. Un proceso visible puede llevar a la negación del crédito aunque haya terminado a tu favor. El ocultamiento elimina ese obstáculo.</p></details>
<details><summary>¿Cuánto cuesta ocultar los antecedentes del SATJE en Ecuador?</summary><p class="faq-answer">Juristam cobra $45 por asesoría inicial (virtual) o $85 presencial. El ocultamiento en el SATJE cuesta $250; en Fiscalía $250; el combo SATJE + Fiscalía $400. Incluye preparación del escrito, presentación, seguimiento y verificación final.</p></details>
<details><summary>¿El ocultamiento funciona si mi proceso fue en Quito pero ahora vivo en Guayaquil?</summary><p class="faq-answer">Sí. La solicitud se presenta ante el juzgado que conoció la causa, no donde vives. Juristam gestiona el trámite completo en cualquier ciudad sin que necesites desplazarte, mediante poder notarial.</p></details>
<details><summary>¿Cuánto tiempo tarda en desaparecer mi nombre del SATJE?</summary><p class="faq-answer">Entre 10 y 30 días hábiles según la ciudad. Guayaquil y Quito hasta 30 días; otras ciudades entre 10 y 20. Etapas: preparación (2-5 días), admisión (1-3 días), resolución del juez (5-20 días), ejecución en sistema (1-3 días).</p></details>
<details><summary>¿Un proceso archivado hace 10 años califica para el ocultamiento?</summary><p class="faq-answer">Sí. La Resolución 043-2024 no establece plazo máximo desde el cierre. Lo que importa es el estado actual: archivado, sobreseído, absuelto, conciliación cumplida o extinguido. Juristam ha tramitado casos de hace más de 10 años.</p></details>
<details><summary>¿El ocultamiento del SATJE es permanente o se puede revertir?</summary><p class="faq-answer">Es permanente. Una vez ejecutada la anonimización, tu nombre deja de aparecer definitivamente. La Resolución 043-2024 no establece mecanismo de reversión automática.</p></details>
<details><summary>¿Puedo hacer el trámite de ocultamiento del SATJE yo mismo sin abogado?</summary><p class="faq-answer">En la práctica es muy difícil. El escrito debe fundamentarse en la Resolución 043-2024, Art. 66 de la Constitución y la Ley de Protección de Datos. Un escrito mal fundamentado resulta en rechazo aunque el caso califique. Juristam prepara el escrito con la fundamentación técnica que los jueces aceptan.</p></details>
<details><summary>¿Si fui sobreseído definitivamente puedo ocultar el proceso del SATJE?</summary><p class="faq-answer">Sí, y es la causal más sólida. La Resolución 043-2024 reconoce que cuando el proceso terminó sin responsabilidad penal, el titular tiene derecho reforzado a la protección de sus datos.</p></details>'

Add-FaqData 'cuanto-cuesta-ocultar-antecedentes-ecuador.html' `
'{"@type":"Question","name":"¿Cuánto cobran en Ecuador por ocultar el nombre del SATJE?","acceptedAnswer":{"@type":"Answer","text":"Juristam cobra $250 por el ocultamiento solo en el SATJE, $250 por el ocultamiento solo en Fiscalía (SIAF), y $400 por el combo que cubre ambos sistemas. Todos los precios incluyen preparación del escrito, presentación ante el juzgado o Fiscalía, seguimiento activo y verificación final de que tu nombre ya no aparece en la consulta pública. No hay costos ocultos adicionales."}},{"@type":"Question","name":"¿La asesoría inicial de $45 es obligatoria o puedo contratar directo el servicio?","acceptedAnswer":{"@type":"Answer","text":"La asesoría inicial de $45 (virtual) o $85 (presencial) no es obligatoria en el sentido legal, pero sí es el primer paso recomendado porque permite confirmar si tu caso califica antes de contratar el servicio completo. En la asesoría Juristam revisa tu situación en el SATJE y en Fiscalía, identifica en qué sistemas apareces y define la estrategia. Si decides continuar, los $45 se descuentan del precio final del servicio."}},{"@type":"Question","name":"¿Por qué sale más barato hacer los dos sistemas juntos que por separado?","acceptedAnswer":{"@type":"Answer","text":"El combo SATJE + Fiscalía cuesta $400 en lugar de $500 que costarían por separado porque parte del trabajo de análisis inicial, documentación y coordinación se comparte entre ambos trámites. Es la opción más eficiente cuando apareces en los dos sistemas, que es el caso más frecuente según la experiencia de Juristam."}},{"@type":"Question","name":"¿El precio incluye todos los gastos o hay que pagar algo adicional en el juzgado?","acceptedAnswer":{"@type":"Answer","text":"El precio de Juristam incluye honorarios profesionales y gestión completa del trámite. En algunos juzgados puede haber tasas administrativas menores de la Función Judicial, que cuando existen son de bajo monto y se informan al cliente antes de iniciar. No hay sorpresas."}},{"@type":"Question","name":"¿Puedo pagar el servicio en cuotas?","acceptedAnswer":{"@type":"Answer","text":"Sí. Juristam ofrece opciones de pago flexible que se coordinan en la asesoría inicial según el caso y el servicio contratado. El anticipo habitual es un porcentaje del total al iniciar el trámite, con el saldo al avanzar o completar el proceso."}},{"@type":"Question","name":"¿Qué pasa si Juristam tramita el caso y el juez lo rechaza?","acceptedAnswer":{"@type":"Answer","text":"Juristam evalúa el caso en la asesoría inicial precisamente para confirmar que califica antes de iniciar el trámite. Si hay duda sobre si procede, se lo comunica al cliente antes de contratar. Cuando el análisis confirma que el caso califica y el escrito está bien fundamentado, la tasa de aprobación es alta."}},{"@type":"Question","name":"¿El costo varía según la ciudad donde fue el proceso?","acceptedAnswer":{"@type":"Answer","text":"El precio base de Juristam es el mismo independientemente de la ciudad donde se tramitó el proceso. Lo que sí puede variar levemente son las gestiones locales si el proceso fue en una ciudad diferente a Guayaquil. Cualquier variación se informa con total transparencia antes de iniciar."}},{"@type":"Question","name":"¿Tengo que ir en persona a la oficina de Juristam para contratar el servicio?","acceptedAnswer":{"@type":"Answer","text":"No. La asesoría virtual cuesta $45 y se hace por videollamada desde cualquier ciudad o país. Todo el trámite posterior puede gestionarse de forma remota mediante poder notarial que puede otorgarse en cualquier notaría del Ecuador o en el consulado si está en el exterior."}},{"@type":"Question","name":"¿El precio es el mismo si tengo varios procesos que ocultar?","acceptedAnswer":{"@type":"Answer","text":"No necesariamente. Cada proceso adicional tiene un análisis y un trámite independiente. En la asesoría inicial Juristam identifica cuántos procesos tienes en el SATJE y en Fiscalía y te da un presupuesto total que puede incluir descuentos por volumen si son varios procesos."}},{"@type":"Question","name":"¿Cuánto tiempo después de pagar empieza el trámite?","acceptedAnswer":{"@type":"Answer","text":"En Juristam el trámite inicia en un plazo de 2 a 5 días hábiles después de coordinar el pago y recibir la documentación necesaria. El proceso completo hasta la verificación final toma entre 10 y 30 días hábiles según la ciudad."}},{"@type":"Question","name":"¿El ocultamiento del SATJE vale la pena si el proceso fue hace más de 5 años?","acceptedAnswer":{"@type":"Answer","text":"Sí, especialmente porque el SATJE no tiene memoria limitada — procesos de hace 10 o 15 años siguen apareciendo en la consulta pública igual que uno de hace un año. Si ese proceso te sigue cerrando puertas de trabajo, crédito o trámites migratorios, el costo del ocultamiento es ampliamente justificado."}},{"@type":"Question","name":"¿Hay algún descuento si soy referido por alguien que ya trabajó con Juristam?","acceptedAnswer":{"@type":"Answer","text":"Juristam tiene un sistema de referidos. Si llegaste recomendado por un cliente anterior, consulta esta condición en la asesoría inicial para que sea aplicada antes de que se defina el precio final del servicio."}}' `
'<details><summary>¿Cuánto cobran en Ecuador por ocultar el nombre del SATJE?</summary><p class="faq-answer">Juristam cobra $250 (SATJE solo), $250 (Fiscalía solo) o $400 el combo ambos sistemas. Incluye preparación del escrito, presentación, seguimiento y verificación final. Sin costos ocultos.</p></details>
<details><summary>¿La asesoría inicial de $45 es obligatoria?</summary><p class="faq-answer">No es obligatoria pero sí recomendada: permite confirmar si tu caso califica antes de contratar. Juristam revisa el SATJE y Fiscalía. Si continúas, los $45 se descuentan del servicio.</p></details>
<details><summary>¿Por qué sale más barato hacer los dos sistemas juntos?</summary><p class="faq-answer">El combo SATJE + Fiscalía cuesta $400 en lugar de $500 porque parte del análisis y documentación se comparte. Es la opción más eficiente cuando apareces en los dos sistemas.</p></details>
<details><summary>¿El precio incluye todos los gastos o hay costos en el juzgado?</summary><p class="faq-answer">El precio de Juristam incluye honorarios y gestión completa. Si hay tasas judiciales menores, se informan antes de iniciar. No hay sorpresas.</p></details>
<details><summary>¿Puedo pagar el servicio en cuotas?</summary><p class="faq-answer">Sí. Juristam ofrece pago flexible coordinado en la asesoría inicial. El anticipo habitual es un porcentaje al iniciar, con el saldo al avanzar el proceso.</p></details>
<details><summary>¿Qué pasa si el juez rechaza la solicitud?</summary><p class="faq-answer">Juristam evalúa el caso antes de iniciar para confirmar que califica. Si hay duda, se comunica antes de contratar. La tasa de aprobación es alta cuando el caso está bien fundamentado.</p></details>
<details><summary>¿El costo varía según la ciudad donde fue el proceso?</summary><p class="faq-answer">El precio base es el mismo en todo Ecuador. Gestiones locales en ciudades distintas a Guayaquil pueden variar levemente. Cualquier variación se informa antes de iniciar.</p></details>
<details><summary>¿Tengo que ir en persona a Juristam?</summary><p class="faq-answer">No. La asesoría virtual es por videollamada desde cualquier lugar. El trámite se gestiona de forma remota mediante poder notarial en cualquier notaría del Ecuador o consulado en el exterior.</p></details>
<details><summary>¿El precio es el mismo si tengo varios procesos?</summary><p class="faq-answer">No necesariamente. Cada proceso adicional tiene un trámite independiente. Juristam identifica cuántos procesos tienes y da un presupuesto total con posibles descuentos por volumen.</p></details>
<details><summary>¿Cuánto tiempo después de pagar empieza el trámite?</summary><p class="faq-answer">En 2 a 5 días hábiles después de coordinar el pago y documentación. El proceso completo toma entre 10 y 30 días hábiles según la ciudad.</p></details>
<details><summary>¿Vale la pena si el proceso fue hace más de 5 años?</summary><p class="faq-answer">Sí. El SATJE no tiene memoria limitada — procesos de hace 15 años siguen apareciendo igual que uno reciente. Si te sigue cerrando puertas de trabajo, crédito o visas, el ocultamiento es ampliamente justificado.</p></details>
<details><summary>¿Hay descuento si soy referido por otro cliente?</summary><p class="faq-answer">Juristam tiene sistema de referidos. Consulta en la asesoría inicial para que sea aplicado antes de definir el precio final.</p></details>'

Add-FaqData 'cuanto-tarda-ocultamiento-satje-ecuador.html' `
'{"@type":"Question","name":"¿Cuánto tiempo demora en desaparecer mi nombre del SATJE después de contratar el trámite?","acceptedAnswer":{"@type":"Answer","text":"El proceso completo toma entre 10 y 30 días hábiles desde que Juristam presenta la solicitud ante el juzgado. El plazo varía por ciudad: Guayaquil y Quito tienen mayor congestión y pueden tomar hasta 30 días hábiles; Cuenca entre 15 y 25; otras ciudades entre 10 y 20. El proceso tiene cuatro etapas: preparación del escrito (2-5 días), admisión (1-3 días), resolución del juez (5-20 días) y ejecución en el sistema (1-3 días)."}},{"@type":"Question","name":"¿Puedo hacer algo para que el trámite del SATJE sea más rápido?","acceptedAnswer":{"@type":"Answer","text":"Sí. Lo que más acelera el proceso es tener toda la documentación lista antes de iniciar: la copia del auto de archivo, sobreseimiento o resolución que acredita el estado del proceso, y los datos exactos del número de causa y juzgado. En Juristam el abogado identifica exactamente qué documentos necesitas en la asesoría inicial para que no haya demoras por documentación incompleta, que es la causa más común de retrasos."}},{"@type":"Question","name":"¿El trámite de Fiscalía tarda lo mismo que el del SATJE?","acceptedAnswer":{"@type":"Answer","text":"No necesariamente. El ocultamiento en Fiscalía se tramita ante la Dirección Jurídica de la Fiscalía General del Estado bajo la Resolución 027-FGE-2024, y en algunos casos puede resolverse más rápido que el SATJE porque el proceso administrativo interno de Fiscalía tiene menos congestión que los juzgados en ciudades grandes. Sin embargo, los tiempos varían según el caso."}},{"@type":"Question","name":"¿Qué pasa si el juez tarda más del plazo establecido en resolver?","acceptedAnswer":{"@type":"Answer","text":"Juristam presenta un escrito de impulso procesal solicitando al juez que resuelva dentro de los plazos legales. Si la demora persiste, hay mecanismos de queja ante el Consejo de la Judicatura. Esta gestión activa de los plazos es parte del servicio de seguimiento que incluye Juristam."}},{"@type":"Question","name":"¿Puedo trabajar o hacer trámites normalmente mientras espero que se complete el ocultamiento?","acceptedAnswer":{"@type":"Answer","text":"Sí. El trámite de ocultamiento no genera ninguna restricción sobre tu vida cotidiana mientras está en proceso. Sin embargo, durante ese período tu nombre sigue visible en el SATJE, por lo que si hay una búsqueda de empleo o trámite urgente, conviene considerar los tiempos."}},{"@type":"Question","name":"¿Desde qué momento exactamente mi nombre deja de aparecer en el SATJE?","acceptedAnswer":{"@type":"Answer","text":"Tu nombre desaparece desde el momento en que el secretario del juzgado ejecuta la resolución de ocultamiento en el sistema. Eso ocurre típicamente 1 a 3 días después de que el juez emite la resolución favorable. Juristam verifica que el ocultamiento esté efectivamente ejecutado antes de dar por cerrado el caso."}},{"@type":"Question","name":"¿El ocultamiento tarda lo mismo si el proceso fue hace 10 años que si fue hace 2 años?","acceptedAnswer":{"@type":"Answer","text":"El tiempo del trámite no varía significativamente por la antigüedad del proceso. Lo que puede variar es la facilidad para conseguir los documentos: procesos muy antiguos pueden tener el expediente en archivo muerto. Juristam gestiona esa obtención de documentos como parte del servicio."}},{"@type":"Question","name":"¿Qué pasa si durante el trámite me buscan para un trabajo y ven mi nombre en el SATJE?","acceptedAnswer":{"@type":"Answer","text":"Si el proceso aún no está ocultado, el empleador podría verlo. En esos casos Juristam puede emitir una carta explicando que el ocultamiento está en trámite bajo la Resolución 043-2024, lo que en algunos contextos puede ser suficiente para que el empleador espere."}},{"@type":"Question","name":"¿Si tengo procesos en dos ciudades distintas, los trámites se hacen al mismo tiempo?","acceptedAnswer":{"@type":"Answer","text":"Sí, pueden tramitarse simultáneamente porque son solicitudes independientes ante juzgados distintos. Juristam coordina ambos trámites en paralelo para minimizar el tiempo total. El plazo final estará determinado por el más lento de los dos."}},{"@type":"Question","name":"¿Si el proceso fue en 2015 y el expediente ya no está en el juzgado activo, el trámite se puede hacer?","acceptedAnswer":{"@type":"Answer","text":"Sí. Los expedientes archivados en archivo muerto siguen siendo recuperables. La secretaría del juzgado puede localizarlo por número de causa aunque no esté en el archivo activo. Juristam conoce los procedimientos para obtener documentación de expedientes históricos."}},{"@type":"Question","name":"¿El trámite de ocultamiento interrumpe o afecta de alguna forma el proceso judicial existente?","acceptedAnswer":{"@type":"Answer","text":"No. El ocultamiento es un trámite incidental que no modifica el proceso judicial original, su resultado ni sus efectos legales. Solo cambia la visibilidad pública del nombre en el sistema de búsqueda."}},{"@type":"Question","name":"¿Cuánto tiempo después de completado el ocultamiento debo esperar para que no aparezca en Google?","acceptedAnswer":{"@type":"Answer","text":"El SATJE desindexado deja de aparecer en nuevas búsquedas de Google a medida que los robots de indexación actualizan su caché, lo que puede tomar entre días y semanas. Sin embargo, si existen capturas anteriores, noticias de prensa u otros sitios que mencionaron el proceso, esos resultados son independientes del SATJE y el ocultamiento no los afecta."}}' `
'<details><summary>¿Cuánto tiempo demora en desaparecer mi nombre del SATJE?</summary><p class="faq-answer">Entre 10 y 30 días hábiles. Guayaquil y Quito hasta 30 días; Cuenca 15-25; otras ciudades 10-20. Etapas: preparación (2-5 días), admisión (1-3), resolución del juez (5-20), ejecución en sistema (1-3 días).</p></details>
<details><summary>¿Puedo hacer algo para que el trámite sea más rápido?</summary><p class="faq-answer">Tener la documentación lista antes de iniciar acelera el proceso. Juristam identifica exactamente qué documentos necesitas en la asesoría inicial para evitar demoras, que es la causa más común de retrasos.</p></details>
<details><summary>¿El trámite de Fiscalía tarda lo mismo que el del SATJE?</summary><p class="faq-answer">No necesariamente. El ocultamiento en Fiscalía bajo la Resolución 027-FGE-2024 puede resolverse más rápido en algunos casos porque el proceso administrativo interno tiene menos congestión que los juzgados.</p></details>
<details><summary>¿Qué pasa si el juez tarda más del plazo en resolver?</summary><p class="faq-answer">Juristam presenta un escrito de impulso procesal. Si la demora persiste, hay mecanismos de queja ante el Consejo de la Judicatura. Esta gestión activa es parte del servicio de seguimiento.</p></details>
<details><summary>¿Puedo trabajar normalmente mientras espero que se complete el ocultamiento?</summary><p class="faq-answer">Sí, sin restricciones. Pero durante ese período tu nombre sigue visible en el SATJE. Si tienes búsqueda de empleo o trámite urgente, Juristam puede orientarte sobre cómo manejar esa ventana.</p></details>
<details><summary>¿Desde qué momento exactamente mi nombre deja de aparecer?</summary><p class="faq-answer">Desde que el secretario ejecuta la resolución en el sistema, típicamente 1-3 días después de la resolución favorable del juez. Juristam verifica que esté ejecutado antes de dar por cerrado el caso.</p></details>
<details><summary>¿El ocultamiento tarda lo mismo para un proceso de hace 10 años?</summary><p class="faq-answer">El tiempo del trámite no varía significativamente. Lo que puede variar es conseguir documentos de procesos muy antiguos en archivo muerto. Juristam gestiona esa obtención como parte del servicio.</p></details>
<details><summary>¿Qué pasa si durante el trámite me buscan para un trabajo?</summary><p class="faq-answer">El empleador podría ver el proceso aún visible. Juristam puede emitir una carta explicando que el ocultamiento está en trámite bajo la Resolución 043-2024 para que el empleador espere.</p></details>
<details><summary>¿Si tengo procesos en dos ciudades se tramitan al mismo tiempo?</summary><p class="faq-answer">Sí. Son solicitudes independientes ante juzgados distintos. Juristam los coordina en paralelo para minimizar el tiempo total.</p></details>
<details><summary>¿Si el expediente ya está en archivo muerto se puede hacer el trámite?</summary><p class="faq-answer">Sí. La secretaría puede localizarlo por número de causa. Juristam conoce los procedimientos para obtener documentación de expedientes históricos y los gestiona como parte del trámite.</p></details>
<details><summary>¿El ocultamiento afecta el proceso judicial existente?</summary><p class="faq-answer">No. Solo cambia la visibilidad pública del nombre en el buscador. El expediente sigue existiendo íntegramente para efectos internos.</p></details>
<details><summary>¿Cuánto tiempo después del ocultamiento deja de aparecer en Google?</summary><p class="faq-answer">Entre días y semanas, según cuándo los robots de Google actualicen su caché. Si hay capturas anteriores o noticias de prensa que mencionaron el proceso, esos resultados son independientes del SATJE.</p></details>'

